INSTALL httpfs; 
INSTALL iceberg; 
LOAD httpfs;  LOAD iceberg;

-- S3/MinIO
-- DROP SECRET minio_s3;
CREATE SECRET minio_s3 (
  TYPE S3,
  PROVIDER config,
  KEY_ID  'admin',
  REGION 'us-east-1',
  SECRET  'password',
  ENDPOINT 'localhost:9000/warehouse',

  USE_SSL false
);

-- DROP SECRET iceberg_rest;
CREATE SECRET iceberg_rest (
  TYPE ICEBERG, TOKEN 'dummy'
);

ATTACH 'warehouse' AS warehouse (
  TYPE ICEBERG,
  ENDPOINT 'http://localhost:8181'
);

USE warehouse.nyc;
